Here's a set of **pytest-style unit tests** for the `deep_get` function. These tests cover:

- **Happy path**: Normal usage with valid nested keys.
- **Edge cases**: Empty key string, keys that don't exist, and nested structures.
- **Error cases**: Non-dictionary input, invalid key types, etc.

### ✅ `test_deep_get.py`

```python
import pytest

def test_deep_get_happy_path():
    data = {"a": {"b": {"c": 42}}}
    assert deep_get(data, "a.b.c") == 42
    assert deep_get(data, "a.b") == {"c": 42}
    assert deep_get(data, "a") == {"b": {"c": 42}}

def test_deep_get_missing_key():
    data = {"a": {"b": {"c": 42}}}
    assert deep_get(data, "a.b.d") is None
    assert deep_get(data, "x.y.z", default="not found") == "not found"

def test_deep_get_empty_keys():
    data = {"a": {"b": {"c": 42}}}
    assert deep_get(data, "") == data
    assert deep_get(data, ".", default="invalid") == data

def test_deep_get_non_dict_input():
    data = [1, 2, 3]
    assert deep_get(data, "0") is None
    assert deep_get(data, "0", default="found") == "found"

def test_deep_get_mixed_types():
    data = {"a": [1, {"b": 2}]}
    assert deep_get(data, "a.1.b") == 2
    assert deep_get(data, "a.1.c") is None
    assert deep_get(data, "a.1.c", default="missing") == "missing"

def test_deep_get_non_string_keys():
    data = {"a": {"b": 42}}
    assert deep_get(data, "a.b") == 42
    assert deep_get(data, 123) is None  # keys should be a string
    assert deep_get(data, 123, default="invalid") == "invalid"

def test_deep_get_key_with_dot():
    data = {"a.b": 42}
    assert deep_get(data, "a.b") == 42
    assert deep_get(data, "a.b.c") is None

def test_deep_get_nested_non_dict():
    data = {"a": {"b": [1, 2, 3]}}
    assert deep_get(data, "a.b.0") == 1
    assert deep_get(data, "a.b.3") is None
```

### ✅ How to Run the Tests

Assuming your `deep_get` function is in a file called `your_module.py`, and the tests are in `test_deep_get.py`, you can run them with:

```bash
pytest test_deep_get.py
```

### ✅ Notes

- The `deep_get` function expects `keys` to be a **string**. If a non-string is passed (e.g., integer), it will be treated as a key, but it's not the intended usage.
- `deep_get` will return `default` if any key in the path is not a `dict` or not present.
- The function is designed for **dot-separated** keys, like `"a.b.c"`.

